        auto_next: { state: 'idle', after: 40 },
        transitions: { use: { next: 'idle' } },
      },
    },
  },
  {
    id: 'desk',
    name: 'desk',
    capacity: 1,
    interactAnim: 'reading',
    position: { tx: 14, ty: 5 },
    interactMs: 8000,
    state: 'idle',
    states: {
      idle: {
        transitions: { use: { next: 'working' } },
      },
      working: {
        speech: 'Time to get some work done.',
        auto_next: { state: 'idle', after: 35 },
        transitions: { use: { next: 'idle' } },
      },
    },
  },
  {
    id: 'bed',
    name: 'bed',
    capacity: 1,
    interactAnim: 'sit2',
    position: { tx: 16, ty: 5 },
    interactMs: 15000,
    state: 'idle',
    states: {
