        auto_next: { state: 'idle', after: 60 },
        transitions: { use: { next: 'idle' } },
      },
    },
  },
  {
    id: 'easel',
    name: 'easel',
    capacity: 1,
    interactAnim: 'phone',
    position: { tx: 2, ty: 7 },
    interactMs: 12000,
    state: 'idle',
    states: {
